  }
];

let nextId = posts.length + 1;

function readPosts() {
  return posts.map((post) => ({ ...post }));
}

const getCachedPosts = unstable_cache(readPosts, ['posts'], {
  tags: ['posts']
});

export function getPosts() {
  return getCachedPosts();
}

